import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.ObjectInputStream;

public class InsecureDeserializationExample {
    public static void main(String[] args) {
        String serializedObject = "rO0ABXNyACRqYXZhLmxhbmcuU3RyaW5nOwAAAAAAAAAAAA=="; // This is a base64 encoded serialized object

        try {
            byte[] serializedData = javax.xml.bind.DatatypeConverter.parseBase64Binary(serializedObject);
            ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(serializedData));
            Object obj = ois.readObject();
            System.out.println("Deserialized object: " + obj);
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

